@extends('layouts.app')@section('content')<h2>Appointments</h2><p class="text-muted">Admin can approve, reject, complete, or cancel appointments here.</p><div class="card"><div class="card-body table-responsive"><table class="table table-striped align-middle"><thead><tr><th>ID</th><th>Patient</th><th>Doctor</th><th>Date</th><th>Reason</th><th>Status</th><th>Admin Action</th></tr></thead><tbody>@forelse($appointments as $a)<tr><td>{{ $a['id'] }}</td><td>{{ $a['user']['fullName'] ?? 'No patient' }}</td><td>{{ $a['doctor']['fullName'] ?? 'No doctor' }}</td><td>{{ substr($a['appointmentDate'],0,10) }}</td><td>{{ $a['reason'] }}</td><td><span class="badge bg-{{ $a['status']=='Approved'?'success':($a['status']=='Rejected'?'warning':($a['status']=='Cancelled'?'danger':($a['status']=='Completed'?'primary':'secondary'))) }}">{{ $a['status'] }}</span></td><td>@if($a['status']=='Pending')<a class="btn btn-sm btn-success" href="/admin/appointments/status/{{ $a['id'] }}/Approved">Accept</a> <a class="btn btn-sm btn-warning" href="/admin/appointments/status/{{ $a['id'] }}/Rejected">Reject</a>@endif @if($a['status']!='Cancelled' && $a['status']!='Completed')<a onclick="return confirm('Cancel this appointment?')" class="btn btn-sm btn-danger" href="/admin/appointments/status/{{ $a['id'] }}/Cancelled">Cancel</a>@endif @if($a['status']=='Approved')<a class="btn btn-sm btn-primary" href="/admin/appointments/status/{{ $a['id'] }}/Completed">Complete</a>@endif</td></tr>@empty<tr><td colspan="7" class="text-center text-muted">No appointments found.</td></tr>@endforelse</tbody></table></div></div>@endsection
